        authPayload: authPayload1,
        spaceId: spaceId1,
        address: addressBookItem1.address,
      });

      await expect(
        dbAddressBookItemsRepository.findOneBy({
          address: addressBookItem1.address,
          space: { id: spaceId2 },
        }),
      ).resolves.toStrictEqual(
        expect.objectContaining({
          id: expect.any(Number),
          address: addressBookItem1.address,
          name: addressBookItem2.name,
